#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

// Inline timer definitions from timer.h
#include <unistd.h>
#include <stdint.h>
#include <stdlib.h>

__inline__ uint64_t rdtsc() 
{
     uint32_t lo, hi;
     __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
     return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#include <sys/time.h>

struct timeval starttime;
struct timeval endtime;

#define startTime() \
{ \
  gettimeofday(&starttime, 0); \
}
#define stopTime(valusecs) \
{ \
  gettimeofday(&endtime, 0); \
  valusecs = (endtime.tv_sec-starttime.tv_sec)*1000000+endtime.tv_usec-starttime.tv_usec; \
}

// End of inline timer definitions

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

#define MIN(a, b) ((a)<=(b) ? (a) : (b))

__global__ void pathfinder_kernel(int* src, int* dst, int* wall_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n >= cols) return;

    int min = src[n];
    if (n > 0) {
        int left = src[n-1];
        if (left < min) min = left;
    }
    if (n < cols-1) {
        int right = src[n+1];
        if (right < min) min = right;
    }
    dst[n] = wall_row[n] + min;
}

void
init(int argc, char** argv)
{
	if(argc==3){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
	}else{
                printf("Usage: pathfiner width num_of_steps\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;
    int *d_src, *d_dst, *d_wall_row;
    int min;

    dst = result;
    src = new int[cols];

    // Allocate CUDA memory
    cudaMalloc(&d_src, cols * sizeof(int));
    cudaMalloc(&d_dst, cols * sizeof(int));
    cudaMalloc(&d_wall_row, cols * sizeof(int));

    // Initialize src with result (first row)
    for(int i=0; i<cols; i++) src[i] = result[i];

    pin_stats_reset();

    int blockSize = 256;
    int numBlocks = (cols + blockSize - 1) / blockSize;

    for (int t = 0; t < rows-1; t++) {
        // Swap logical pointers
        temp = src;
        src = dst;
        dst = temp;

        // Copy current src data to device
        cudaMemcpy(d_src, src, cols * sizeof(int), cudaMemcpyHostToDevice);

        // Copy next wall row to device
        cudaMemcpy(d_wall_row, wall[t+1], cols * sizeof(int), cudaMemcpyHostToDevice);

        // Launch kernel
        pathfinder_kernel<<<numBlocks, blockSize>>>(d_src, d_dst, d_wall_row, cols);

        // Copy result back to host dst
        cudaMemcpy(dst, d_dst, cols * sizeof(int), cudaMemcpyDeviceToHost);
    }

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

#ifdef BENCH_PRINT

    for (int i = 0; i < cols; i++)

            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; i < cols; i++)

            printf("%d ",dst[i]) ;

    printf("\n") ;

#endif

    // Cleanup host memory
    delete [] data;
    // wall is an array of pointers pointing into data, so deleting data covers the content. 
    // However, the array of pointers itself needs deletion if allocated separately, 
    // but here wall[n] = data + ..., so wall is just an array of pointers.
    // The original code does `delete [] wall;` which deletes the pointer array.
    delete [] wall;
    delete [] dst;
    delete [] src;

    // Cleanup device memory
    cudaFree(d_src);
    cudaFree(d_dst);
    cudaFree(d_wall_row);
}
